"""EEGNet Deep Learning Model"""

class EEGNet(nn.Module):

    def __init__(self):

        super().__init__()

        self.conv1 = nn.Conv2d(
            1,
            16,
            kernel_size=(1, 64),
            padding=(0, 32)
        )

        self.batchnorm1 = nn.BatchNorm2d(16)

        self.pool = nn.AvgPool2d(
            (1, 4)
        )

        self.dropout = nn.Dropout(
            0.25
        )

        self.fc = nn.Linear(
            12672,
            len(np.unique(y))
        )

    def forward(self, x):

        x = torch.relu(
            self.batchnorm1(
                self.conv1(x)
            )
        )

        x = self.pool(x)

        x = self.dropout(x)

        x = x.view(
            x.size(0),
            -1
        )

        x = self.fc(x)

        return x

"""Initialize EEGNet"""

model = EEGNet()

criterion = nn.CrossEntropyLoss()

optimizer = optim.Adam(
    model.parameters(),
    lr=0.001
)

