"""EEGNet Prediction"""

class AdvancedEEGNet(nn.Module):

    def __init__(self, num_classes):

        super().__init__()

        self.features = nn.Sequential(

            nn.Conv2d(
                1,
                32,
                kernel_size=(1, 64),
                padding=(0, 32)
            ),

            nn.BatchNorm2d(32),

            nn.ReLU(),

            nn.Conv2d(
                32,
                64,
                kernel_size=(1, 16),
                padding=(0, 8)
            ),

            nn.BatchNorm2d(64),

            nn.ReLU(),

            nn.AvgPool2d((1,4)),

            nn.Dropout(0.5)

        )

        self._to_linear = None

        self._initialize_shape()

        self.classifier = nn.Sequential(

            nn.Linear(
                self._to_linear,
                128
            ),

            nn.ReLU(),

            nn.Dropout(0.5),

            nn.Linear(
                128,
                num_classes
            )
        )

    def _initialize_shape(self):

        with torch.no_grad():

            sample = torch.randn(
                1,
                1,
                X_multi.shape[1],
                X_multi.shape[2]
            )

            sample = self.features(sample)

            self._to_linear = sample.view(
                1,
                -1
            ).shape[1]

    def forward(self, x):

        x = self.features(x)

        x = x.view(
            x.size(0),
            -1
        )

        x = self.classifier(x)

        return x

