cv_accuracies = []
fold = 1

for train_idx, test_idx in kf.split(X_dl_multi):

    print(f'Fold {fold}')

    X_train_fold = X_dl_multi[train_idx]
    X_test_fold = X_dl_multi[test_idx]

    y_train_fold = y_multi[train_idx]
    y_test_fold = y_multi[test_idx]

    X_train_tensor = torch.tensor(
        X_train_fold,
        dtype=torch.float32
    )

    X_test_tensor = torch.tensor(
        X_test_fold,
        dtype=torch.float32
    )

    y_train_tensor = torch.tensor(
        y_train_fold,
        dtype=torch.long
    )

    y_test_tensor = torch.tensor(
        y_test_fold,
        dtype=torch.long
    )

    train_dataset = TensorDataset(
        X_train_tensor,
        y_train_tensor
    )

    train_loader = DataLoader(
        train_dataset,
        batch_size=32,
        shuffle=True
    )

    model_cv = AdvancedEEGNet(
        num_classes=2
    )

    criterion = nn.CrossEntropyLoss()

    optimizer = optim.Adam(
        model_cv.parameters(),
        lr=0.001
    )

    # Training
    for epoch in range(5):

        model_cv.train()

        for batch_x, batch_y in train_loader:

            optimizer.zero_grad()

            outputs = model_cv(batch_x)

            loss = criterion(
                outputs,
                batch_y
            )

            loss.backward()

            optimizer.step()

    # Evaluation
    model_cv.eval()

    with torch.no_grad():

        outputs = model_cv(
            X_test_tensor
        )

        _, preds = torch.max(
            outputs,
            1
        )

    acc = accuracy_score(
        y_test_fold,
        preds.numpy()
    )

    print("Accuracy:", acc)

    cv_accuracies.append(acc)

    fold += 1

